let q = require('q');

describe('test q', function() {
    it('test q.nextTick.runAfter executes task asynchronously', function(done) {
        let executed = false;
        let task = function() {
            executed = true;
        };

        q.nextTick.runAfter(task);

        // Task should not be executed immediately
        assert.strictEqual(executed, false);

        // Check that task is executed on next tick
        process.nextTick(function() {
            assert.strictEqual(executed, true);
            done();
        });
    });

    it('test q.nextTick.runAfter executes multiple tasks in order', function(done) {
        let results = [];

        let task1 = function() { results.push(1); };
        let task2 = function() { results.push(2); };
        let task3 = function() { results.push(3); };

        q.nextTick.runAfter(task1);
        q.nextTick.runAfter(task2);
        q.nextTick.runAfter(task3);

        process.nextTick(function() {
            assert.deepStrictEqual(results, [1, 2, 3]);
            done();
        });
    });

    it('test q.nextTick.runAfter handles task with parameters', function(done) {
        let result = null;
        let task = function(value) {
            result = value;
        };

        q.nextTick.runAfter(function() {
            task('test-value');
        });

        process.nextTick(function() {
            assert.strictEqual(result, 'test-value');
            done();
        });
    });

    it('test q.nextTick.runAfter handles task that throws error', function(done) {
        let errorThrown = false;
        let task = function() {
            throw new Error('Test error');
        };

        // Capture uncaught exceptions temporarily
        let originalHandler = process.listeners('uncaughtException');
        process.removeAllListeners('uncaughtException');

        process.once('uncaughtException', function(err) {
            errorThrown = true;
            assert.strictEqual(err.message, 'Test error');

            // Restore original handlers
            originalHandler.forEach(handler => {
                process.on('uncaughtException', handler);
            });

            done();
        });

        q.nextTick.runAfter(task);
    });

    it('test q.nextTick.runAfter with empty function', function(done) {
        let task = function() {
            // Empty function
        };

        q.nextTick.runAfter(task);

        process.nextTick(function() {
            // If we reach here, the empty task executed without issues
            assert.ok(true);
            done();
        });
    });
