describe('test q', function() {
    it('test q.defer creates a deferred object with promise, resolve, and reject', function(done) {
        let deferred = q.defer();

        // Check that deferred has the expected properties
        assert(deferred.promise, 'deferred should have a promise property');
        assert(typeof deferred.resolve === 'function', 'deferred should have a resolve function');
        assert(typeof deferred.reject === 'function', 'deferred should have a reject function');

        done();
    });

    it('test q.defer resolve functionality', function(done) {
        let deferred = q.defer();
        let testValue = 'test result';

        deferred.promise.then(function(result) {
            assert.strictEqual(result, testValue, 'resolved value should match');
            done();
        }).catch(done);

        deferred.resolve(testValue);
    });

    it('test q.defer reject functionality', function(done) {
        let deferred = q.defer();
        let testError = new Error('test error');

        deferred.promise.then(function() {
            done(new Error('Promise should have been rejected'));
        }).catch(function(error) {
            assert.strictEqual(error, testError, 'rejected error should match');
            done();
        });

        deferred.reject(testError);
    });

    it('test q.defer promise state after resolve', function(done) {
        let deferred = q.defer();
        let resolved = false;

        deferred.promise.then(function(result) {
            resolved = true;
            assert.strictEqual(result, 42, 'should resolve with correct value');

            // Try to resolve again - should not change the result
            deferred.resolve(100);

            setTimeout(function() {
                assert(resolved, 'promise should remain resolved');
                done();
            }, 10);
        }).catch(done);

        deferred.resolve(42);
    });

    it('test q.defer with multiple then handlers', function(done) {
        let deferred = q.defer();
        let handler1Called = false;
        let handler2Called = false;

        deferred.promise.then(function(result) {
            handler1Called = true;
            assert.strictEqual(result, 'shared result');
        });

        deferred.promise.then(function(result) {
            handler2Called = true;
            assert.strictEqual(result, 'shared result');

            // Check both handlers were called
            assert(handler1Called, 'first handler should be called');
            assert(handler2Called, 'second handler should be called');
            done();
        }).catch(done);

        deferred.resolve('shared result');
    });
});
