        }, delay);

        deferred.promise.then(function(value) {
            var elapsed = Date.now() - startTime;
            assert(elapsed >= delay - 10, 'should wait at least the delay time'); // -10ms tolerance
            assert.equal(value, 'delayed result', 'should resolve with correct value');
            done();
        }).catch(done);
    });

