            done();
        }).catch(done);
    });

    it('test q.makePromise.prototype.dispatch - operation with rejection', function(done) {
        let mockPromise = {
            promiseDispatch: function(resolve, op, args) {
                // Simulate operation that calls reject instead of resolve
                let defer = q.defer();
                defer.reject(new Error('Operation failed'));
                // Since dispatch expects resolve to be called, we'll call it with the rejected promise
                resolve(defer.promise);
            }
        };

        let dispatch = q.makePromise.prototype.dispatch.bind(mockPromise);
        let promise = dispatch('failingOp', []);

        promise.then(function(result) {
            // The result should be a rejected promise
            return result;
        }).then(function() {
            done(new Error('Expected promise to be rejected'));
        }).catch(function(error) {
            assert.equal(error.message, 'Operation failed');
            done();
        });
    });

    it('test q.makePromise.prototype.dispatch - async execution with nextTick', function(done) {
        let executionOrder = [];

        let mockPromise = {
            promiseDispatch: function(resolve, op, args) {
                executionOrder.push('promiseDispatch');
                resolve('async result');
            }
        };

        let dispatch = q.makePromise.prototype.dispatch.bind(mockPromise);

        executionOrder.push('before dispatch');
        let promise = dispatch('test', []);
        executionOrder.push('after dispatch');

        promise.then(function(result) {
            executionOrder.push('promise resolved');

            // Verify that promiseDispatch was called asynchronously
            assert.deepEqual(executionOrder, [
                'before dispatch',
                'after dispatch', 
                'promiseDispatch',
                'promise resolved'
            ]);
            assert.equal(result, 'async result');
            done();
