        deferred.notify(50);
        deferred.notify(100);

        // Resolve the promise
        deferred.resolve('completed');

        promise.then(function(result) {
            assert.equal(result, 'completed');
            assert.deepEqual(progressValues, [10, 50, 100]);
            done();
        }).catch(done);
    });

    it('test q.progress - progress with object data', function(done) {
        let deferred = q.defer();
        let progressData = [];

        let promise = deferred.promise.progress(function(data) {
            progressData.push(data);
        });

        // Notify with object progress
        deferred.notify({ step: 1, message: 'Starting' });
        deferred.notify({ step: 2, message: 'Processing' });
        deferred.notify({ step: 3, message: 'Finishing' });

        deferred.resolve('done');

        promise.then(function(result) {
            assert.equal(result, 'done');
            assert.equal(progressData.length, 3);
            assert.equal(progressData[0].step, 1);
            assert.equal(progressData[1].message, 'Processing');
            assert.equal(progressData[2].step, 3);
            done();
        }).catch(done);
    });

    it('test q.progress - no progress notifications when resolved immediately', function(done) {
        let deferred = q.defer();
        let progressCalled = false;

        // Resolve immediately
        deferred.resolve('immediate');

        let promise = deferred.promise.progress(function(value) {
            progressCalled = true;
        });

        // Try to notify after resolution (should be ignored)
        deferred.notify('should be ignored');

        promise.then(function(result) {
            assert.equal(result, 'immediate');
            assert.equal(progressCalled, false);
            done();
        }).catch(done);
    });

    it('test q.progress - progress stops after rejection', function(done) {
        let deferred = q.defer();
        let progressValues = [];

        let promise = deferred.promise.progress(function(value) {
            progressValues.push(value);
        });

        // Notify some progress
        deferred.notify('step1');
        deferred.notify('step2');

        // Reject the promise
        deferred.reject(new Error('failed'));

        // Try to notify after rejection (should be ignored)
        deferred.notify('should be ignored');

        promise.then(function() {
            done(new Error('Should not resolve'));
        }).catch(function(error) {
            assert.equal(error.message, 'failed');
            assert.deepEqual(progressValues, ['step1', 'step2']);
            done();
        });
    });
