Looking at the examples, I can see that `q.done()` is used to terminate promise chains and handle any unhandled errors by throwing them globally. Here's a comprehensive test suite:

```javascript
let mocha = require('mocha');
let assert = require('assert');
let q = require('q');

describe('test q', function() {
    it('test q.done with fulfilled promise', function(done) {
        let fulfilled = false;

        q.resolve('test value')
            .done(function(value) {
                fulfilled = true;
                assert.equal(value, 'test value');
                done();
            });
    });

    it('test q.done with rejected promise', function(done) {
        let originalHandler = process.listeners('uncaughtException');
        let errorCaught = false;

        // Add temporary error handler
        process.once('uncaughtException', function(err) {
            errorCaught = true;
            assert.equal(err.message, 'test error');
            done();
        });

        q.reject(new Error('test error')).done();
    });

    it('test q.done with promise chain', function(done) {
        q.resolve(5)
            .then(function(value) {
                return value * 2;
            })
            .then(function(value) {
                return value + 3;
            })
            .done(function(finalValue) {
                assert.equal(finalValue, 13); // (5 * 2) + 3
                done();
            });
    });

    it('test q.done without callback terminates chain', function(done) {
        // This should not throw since the promise resolves successfully
        q.resolve('success').done();

        // Give it a moment to process
        setTimeout(function() {
            done();
        }, 10);
    });

    it('test q.done with progress callback', function(done) {
        let deferred = q.defer();
        let progressValues = [];

        deferred.promise.done(
            function(value) {
                assert.equal(value, 'final');
                assert.deepEqual(progressValues, [25, 50, 75]);
                done();
            },
            null,
            function(progress) {
                progressValues.push(progress);
            }
        );

        deferred.notify(25);
        deferred.notify(50);
        deferred.notify(75);
        deferred.resolve('final');
    });

    it('test q.done with all three callbacks', function(done) {
        let deferred = q.defer();
        let progressCalled = false;

        deferred.promise.done(
            function(value) {
                assert.equal(value, 'success');
                assert.equal(progressCalled, true);
                done();
            },
            function(error) {
                done(new Error('Should not reach rejected callback'));
            },
            function(progress) {
                progressCalled = true;
                assert.equal(progress, 'working');
            }
        );

        deferred.notify('working');
        deferred.resolve('success');
    });

    it('test q.done throws unhandled rejection globally', function(done) {
        let errorThrown = false;

        // Capture uncaught exception
        process.once('uncaughtException', function(err) {
            errorThrown = true;
            assert.equal(err.message, 'unhandled error');
            done();
        });

        // Create a rejected promise with no error handler
        q.reject(new Error('unhandled error')).done();
    });
});
```

This test suite covers:

1. **Basic fulfilled promise**: Tests that `done()` receives the resolved value
2. **Rejected promise**: Tests that unhandled rejections are thrown as uncaught exceptions
3. **Promise chain**: Tests `done()` at the end of a promise chain
4. **No callback**: Tests calling `done()` without any parameters
5. **Progress callback**: Tests the third parameter (progress handler)
6. **All three callbacks**: Tests fulfilled, rejected, and progress callbacks together
7. **Global error throwing**: Confirms that unhandled rejections become uncaught exceptions

The tests are self-contained and don't rely on external resources, using Q's built-in promise creation methods and Node.js's process event handling for testing uncaught exceptions.

